36	// ParseRateLimitHeaders parses the common rate-limit headers emitted by
37	// subprocess harnesses that wrap provider HTTP calls. The harness name selects
38	// the header family. Headers not recognised by the mapping are ignored.
39	//
40	// Supported families:
41	//   - "claude": anthropic-ratelimit-tokens-{limit,remaining,reset} and
42	//     anthropic-ratelimit-requests-{limit,remaining,reset}. The tokens family
43	//     wins when both are present.
44	//   - "codex":  x-ratelimit-{limit,remaining,reset}-tokens (OpenAI/codex).
45	//
46	// Unknown harnesses return an empty signal.
47	func ParseRateLimitHeaders(harness string, headers map[string][]string) RateLimitSignal {
48		h := normalizeHeaders(headers)
49		sig := emptyRateLimitSignal()
50		switch strings.ToLower(strings.TrimSpace(harness)) {
51		case "claude", "anthropic":
52			sig = parseClaudeRateLimit(h)
53		case "codex", "openai":
54			sig = parseCodexRateLimit(h)
55		}
56		return sig
57	}
58	
59	func emptyRateLimitSignal() RateLimitSignal {
60		return RateLimitSignal{
61			CeilingTokens:        -1,
62			CeilingWindowSeconds: -1,
63			Remaining:            -1,
64		}
65	}
66	
67	// normalizeHeaders lowercases and flattens map[string][]string → map[string]string.
68	// The first value for each header wins.
69	func normalizeHeaders(headers map[string][]string) map[string]string {
70		out := make(map[string]string, len(headers))
71		for k, v := range headers {
72			if len(v) == 0 {
73				continue
74			}
75			out[strings.ToLower(strings.TrimSpace(k))] = strings.TrimSpace(v[0])
76		}
77		return out
78	}
