80	// parseClaudeRateLimit reads the anthropic-ratelimit-* header family.
81	// Anthropic publishes separate windows for tokens and requests; tokens is the
82	// more useful signal for "will we run out soon", so we prefer it.
83	func parseClaudeRateLimit(h map[string]string) RateLimitSignal {
84		sig := emptyRateLimitSignal()
85		if limit, ok := parseIntHeader(h, "anthropic-ratelimit-tokens-limit"); ok {
86			sig.CeilingTokens = limit
87		}
88		if rem, ok := parseIntHeader(h, "anthropic-ratelimit-tokens-remaining"); ok {
89			sig.Remaining = rem
90		}
91		if resetStr, ok := h["anthropic-ratelimit-tokens-reset"]; ok {
92			if t, ok2 := parseResetTimestamp(resetStr); ok2 {
93				sig.ResetAt = t
94			}
95		}
96		// If tokens family not populated, fall back to requests family for resetAt/window.
97		if sig.CeilingTokens < 0 && sig.Remaining < 0 {
98			if limit, ok := parseIntHeader(h, "anthropic-ratelimit-requests-limit"); ok {
99				sig.CeilingTokens = limit
100			}
101			if rem, ok := parseIntHeader(h, "anthropic-ratelimit-requests-remaining"); ok {
102				sig.Remaining = rem
103			}
104			if resetStr, ok := h["anthropic-ratelimit-requests-reset"]; ok {
105				if t, ok2 := parseResetTimestamp(resetStr); ok2 {
106					sig.ResetAt = t
107				}
108			}
109		}
110		if sig.HasAny() {
111			// Anthropic rate-limit windows are published as 1-minute buckets for
112			// token-level quotas. Record the window so clients can render "/ min".
113			sig.CeilingWindowSeconds = 60
114		}
115		return sig
116	}
