138	func parseIntHeader(h map[string]string, key string) (int, bool) {
139		v, ok := h[key]
140		if !ok || v == "" {
141			return 0, false
142		}
143		n, err := strconv.Atoi(v)
144		if err != nil {
145			return 0, false
146		}
147		return n, true
148	}
