494	// processResult converts execution output to a Result.
495	func (r *Runner) processResult(harnessName, model string, harness harnessConfig, execResult *ExecResult, execErr error, elapsed time.Duration, ctx context.Context) *Result {
496		result := &Result{
497			Harness:    harnessName,
498			Model:      model,
499			DurationMS: int(elapsed.Milliseconds()),
500		}
501	
502		if execResult != nil {
503			result.Output = execResult.Stdout
504			result.Stderr = execResult.Stderr
505			result.ExitCode = execResult.ExitCode
506		}
507	
508		if execResult != nil && execResult.EarlyCancel {
509			result.Error = fmt.Sprintf("cancelled: auth/rate-limit detected (%s)", execResult.CancelReason)
510			result.ExitCode = -1
511		} else if execResult != nil && execResult.WallClockTimeout {
512			// Wall-clock cap fired regardless of stream activity; distinguish
513			// this from the resettable idle timer so operators can tell the two
514			// failure modes apart in result.json and session logs.
515			reportedElapsed := execResult.WallClockElapsed
516			if reportedElapsed == 0 {
517				reportedElapsed = elapsed
518			}
519			result.Error = fmt.Sprintf("wall-clock deadline exceeded after %v", reportedElapsed.Round(time.Second))
520			result.ExitCode = -1
521		} else if execErr != nil {
522			if errors.Is(execErr, context.DeadlineExceeded) || errors.Is(ctx.Err(), context.DeadlineExceeded) {
523				result.Error = fmt.Sprintf("timeout after %v", elapsed.Round(time.Second))
524				result.ExitCode = -1
525			} else {
526				result.Error = execErr.Error()
527				if result.ExitCode == 0 {
528					result.ExitCode = -1
529				}

