54	type executionWallClockKey struct{}
55	
56	// withExecutionWallClock attaches an absolute wall-clock deadline to ctx.
57	// Unlike withExecutionTimeout — which is an idle (inactivity) timer that
58	// resets on every stream byte or event — this bound fires regardless of
59	// activity so a chatty provider cannot pin the worker indefinitely.
60	func withExecutionWallClock(ctx context.Context, wallClock time.Duration) context.Context {
61		if wallClock <= 0 {
62			return ctx
63		}
64		return context.WithValue(ctx, executionWallClockKey{}, wallClock)
65	}
