77	// authCancelPatterns are regexps matched against lowercased stderr lines that indicate
78	// the subprocess will never succeed and should be cancelled immediately.
79	// Numeric HTTP codes use word-boundary anchors to avoid false positives (e.g. "port 4290").
80	// Overly broad patterns like "credential" and "please run" are intentionally excluded.
81	var authCancelPatterns = []*regexp.Regexp{
82		regexp.MustCompile(`\b429\b`),
83		regexp.MustCompile(`\b401\b`),
84		regexp.MustCompile(`\b403\b`),
85		regexp.MustCompile(`rate limit`),
86		regexp.MustCompile(`ratelimit`),
87		regexp.MustCompile(`quota exceeded`),
88		regexp.MustCompile(`quota_exceeded`),
89		regexp.MustCompile(`not logged in`),
90		regexp.MustCompile(`not signed in`),
91		regexp.MustCompile(`no credentials`),
92		regexp.MustCompile(`authentication required`),
93		regexp.MustCompile(`authentication failed`),
94		regexp.MustCompile(`unauthorized`),
95		regexp.MustCompile(`unauthenticated`),
96		regexp.MustCompile(`invalid api key`),
97		regexp.MustCompile(`invalid_api_key`),
98		regexp.MustCompile(`api key not found`),
99		regexp.MustCompile(`insufficient credits`),
100		regexp.MustCompile(`insufficient_credits`),
101		regexp.MustCompile(`login required`),
102		regexp.MustCompile(`api key expired`),
103		regexp.MustCompile(`token expired`),
104	}
105	
106	// matchesCancelPattern returns the matched pattern string if line matches a known
107	// auth/rate-limit pattern that warrants early cancellation, empty string otherwise.
108	func matchesCancelPattern(line string) string {
109		lower := strings.ToLower(line)
110		for _, p := range authCancelPatterns {
111			if p.MatchString(lower) {
112				return p.String()
113			}
114		}
115		return ""
116	}
